/**
 * Banque de mots / expressions difficiles + leur vraie definition, embarquee
 * "en dur" dans le worker (cf. demande : la vraie definition est codee, puis
 * revelee en fin de manche).
 *
 * Regles de redaction des definitions :
 *   - concises (1 a 2 propositions), style dictionnaire
 *   - pas le mot lui-meme dans sa definition
 *   - francais courant, sens principal du terme
 *
 * Le tirage evite les repetitions au sein d'une meme partie (cf. drawWord).
 *
 * Organisation : entrees regroupees par categorie (adjectifs rares, noms
 * savants, verbes litteraires, termes specialises, expressions imagees...)
 * pour faciliter la maintenance. L'ordre interne n'a pas d'importance au
 * runtime (le tirage est aleatoire).
 */

export interface WordEntry {
  /** Le mot ou l'expression a definir (affiche tel quel aux joueurs). */
  word: string;
  /**
   * Liste des definitions officielles du mot. Toujours au moins une entree
   * (la def principale, celle qui sert de reference au jeu). Pour les mots
   * polysemiques on peut en avoir 2 ou 3 (max 3) afin que les joueurs qui
   * proposeraient un autre sens reel ne soient pas penalises injustement
   * au reveal.
   */
  definitions: [string] | [string, string] | [string, string, string];
  /**
   * Difficulte 1 (tres accessible, vocabulaire quotidien) a 5 (rarissime,
   * archaique ou tres specialise).
   */
  difficulty: 1 | 2 | 3 | 4 | 5;
}

